+): Task<U[], E>;
+export function traverseSerial<T, U, E>(
+  fn: (item: T) => Task<U, E>
+): (items: Iterable<T>) => Task<U[], E>;
+export function traverseSerial<T, U, E>(
+  itemsOrFn: Iterable<T> | ((item: T) => Task<U, E>),
+  taskFn?: (item: T) => Task<U, E>
+): Task<U[], E> | ((items: Iterable<T>) => Task<U[], E>) {
+  if (taskFn === undefined) return (items) => traverseSerial(items, itemsOrFn as (item: T) => Task<U, E>);
+  return new Task((resolve, reject) => {
+    void (async () => {
+      const values: U[] = [];
+      for (const item of itemsOrFn as Iterable<T>) {
+        const outcome = await taskFn(item);
+        if (outcome.isErr) {
+          reject(outcome.error);
+          return;
+        }
