+  maybeFn?: (value: T) => void
+): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
+  if (maybeFn === undefined) return (task) => task.inspect(taskOrFn as (value: T) => void);
+  return (taskOrFn as Task<T, E>).inspect(maybeFn);
+}
+
+/** Run a side effect on rejection while preserving the task's reason. */
+export function tapRejected<T, E>(task: Task<T, E>, fn: (reason: E) => void): Task<T, E>;
+export function tapRejected<T, E>(fn: (reason: E) => void): (task: Task<T, E>) => Task<T, E>;
+export function tapRejected<T, E>(
+  taskOrFn: Task<T, E> | ((reason: E) => void),
+  maybeFn?: (reason: E) => void
+): Task<T, E> | ((task: Task<T, E>) => Task<T, E>) {
+  if (maybeFn === undefined) return (task) => task.inspectRejected(taskOrFn as (reason: E) => void);
+  return (taskOrFn as Task<T, E>).inspectRejected(maybeFn);
+}
+
+/** Retry a task-producing function up to `n` additional times after rejection. */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  function attempt(remaining: number): Task<T, E> {
+    return fn().orElse((reason) => (remaining > 0 ? attempt(remaining - 1) : Task.reject(reason)));
+  }
+  return attempt(Math.max(0, n));
+}
